class Solution(object):
    def constructArray(self, n, k):
        result = list(range(1, n - k + 1))
        left, right = n - k + 1, n
        while left <= right:
            result.append(left)
            left += 1
            if left <= right:
                result.append(right)
                right -= 1
        return result
